import React, { useState } from "react";
import { Container, Paper, Typography, TextField, Button, Alert, CircularProgress } from "@mui/material";
import { useNavigate } from "react-router-dom";
import { sendOtp } from "../services/api";

export default function RiderLogin() {
  const navigate = useNavigate();
  const [mobile, setMobile] = useState("");
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");
    setSuccess("");
    setLoading(true);

    try {
      const res = await sendOtp(mobile, "rider");
      if (res.data.success) {
        setSuccess("OTP sent! Please check your phone.");
        localStorage.setItem("riderMobile", mobile);
        navigate("/rider-otp-login"); // navigate to OTP page
      }
    } catch (err) {
      console.error(err);
      const msg = err.response?.data?.message || "Server error. Try again later.";
      setError(msg);
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="xs">
      <Paper sx={{ mt: 6, p: 4, borderRadius: 3, textAlign: "center", boxShadow: 5 }}>
        <Typography variant="h4" sx={{ mb: 2 }}>Rider Login</Typography>

        {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}
        {success && <Alert severity="success" sx={{ mb: 2 }}>{success}</Alert>}

        <form onSubmit={handleSubmit}>
          <TextField
            fullWidth
            label="Mobile Number"
            value={mobile}
            onChange={(e) => setMobile(e.target.value)}
            margin="normal"
            inputProps={{ maxLength: 10 }}
            required
          />

          <Button
            type="submit"
            fullWidth
            variant="contained"
            sx={{ mt: 3, bgcolor: "black", fontWeight: "bold" }}
            disabled={loading}
          >
            {loading ? <CircularProgress size={24} color="inherit" /> : "Send OTP"}
          </Button>
        </form>

        <Typography sx={{ mt: 2 }}>
          Don’t have an account?{" "}
          <Button onClick={() => navigate("/rider-register")} sx={{ fontWeight: "bold" }}>
            Register
          </Button>
        </Typography>
        <Typography sx={{ mt: 1 }}>
          Login as User?{" "}
          <Button onClick={() => navigate("/login")} sx={{ fontWeight: "bold" }}>
            User Login
          </Button>
        </Typography>
      </Paper>
    </Container>
  );
}
